@namespace Lumeo
@typeparam TItem
@implements IAsyncDisposable
@inject Lumeo.Services.IComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<div id="@_containerId" role="list" class="@CssClass" data-sortable-group="@Group" @attributes="AdditionalAttributes">
    @foreach (var (item, index) in _items.Select((x, i) => (x, i)))
    {
        <div @key="@KeyFor(item, index)" role="listitem" class="@GetItemClass(index)"
             data-sortable-item
             data-sortable-index="@index"
             draggable="@(!Disabled ? "true" : "false")"
             @ondragstart="() => OnDragStart(index)"
             @ondragover:preventDefault="true"
             @ondragover="() => OnDragOver(index)"
             @ondragleave="OnDragLeave"
             @ondrop="() => OnDrop(index)"
             @ondragend="OnDragEnd">
            @if (Handle && !Disabled)
            {
                <div id="@HandleId(index)"
                     class="flex-shrink-0 cursor-grab active:cursor-grabbing text-muted-foreground hover:text-foreground me-2 flex items-center justify-center h-11 w-11 -my-2 sm:h-6 sm:w-6 sm:my-0 rounded focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1"
                     role="button" aria-label="@L["Sortable.DragHandleItem", index + 1, _items.Count]"
                     aria-keyshortcuts="ArrowUp ArrowDown Home End" tabindex="0"
                     @onkeydown="e => OnHandleKeyDown(e, index)">
                    <SvgGlyph Svg="@(LumeoIcons.GripVertical)" class="h-4 w-4" />
                </div>
            }
            <div class="flex-1 min-w-0">
                @if (ItemTemplate is not null)
                {
                    @ItemTemplate(item)
                }
            </div>
        </div>
    }
</div>

@* #40 (a11y): visually-hidden live region announces keyboard / touch reorders to
   assistive tech. Drag/touch/keyboard moves would otherwise be silent. Polite so
   it does not interrupt other speech; aria-atomic re-reads the whole message. *@
<span aria-live="polite" aria-atomic="true" class="sr-only">@_reorderAnnouncement</span>

@code {
    /// <summary>The items rendered as reorderable rows. Two-way bindable via <see cref="ItemsChanged"/>, which also fires after a drag/touch/keyboard reorder.</summary>
    [Parameter] public List<TItem> Items { get; set; } = [];
    /// <summary>Raised with the freshly-reordered list whenever an item is moved, via drag, touch, or keyboard.</summary>
    [Parameter] public EventCallback<List<TItem>> ItemsChanged { get; set; }
    /// <summary>Render fragment for each item's content, receiving the item.</summary>
    [Parameter] public RenderFragment<TItem>? ItemTemplate { get; set; }
    /// <summary>Restricts dragging to a dedicated grip handle on each row instead of the whole row. Default <see langword="true"/>.</summary>
    [Parameter] public bool Handle { get; set; } = true;
    /// <summary>Disables drag, touch, and keyboard reordering, rendering the list as static.</summary>
    [Parameter] public bool Disabled { get; set; }

    /// <summary>
    /// Optional shared-group name. When set, it is emitted on the container as a
    /// <c>data-sortable-group</c> attribute so groups are observable in the DOM.
    /// NOTE: cross-list transfer between lists that share a group is NOT yet
    /// implemented — the attribute is reserved for that future capability and
    /// current behaviour is intra-list reordering only.
    /// </summary>
    [Parameter] public string? Group { get; set; }

    /// <summary>
    /// Raised in addition to <see cref="ItemsChanged"/> whenever an item is
    /// reordered (via drag, touch, or keyboard), carrying the moved item along
    /// with its old and new indices. Does not change the <see cref="ItemsChanged"/>
    /// contract.
    /// </summary>
    [Parameter] public EventCallback<SortableMoved> OnReorder { get; set; }

    /// <summary>
    /// Optional selector that returns a stable, unique key for each item.
    /// Providing this ensures Blazor's diffing engine tracks items by identity
    /// rather than index — critical for drag-reorder to map DOM state correctly.
    /// If omitted, the item reference itself is used as the key.
    /// </summary>
    [Parameter] public Func<TItem, object>? Key { get; set; }

    /// <summary>Additional CSS classes merged onto the list container.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Captures any unmatched attributes and applies them to the list container.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _containerId = LumeoIds.New("sortable");
    private List<TItem> _items = [];
    // #144 (state-on-data-change): the last *parameter* Items instance we saw, NOT
    // the live reordered _items. A reorder mutates _items in place and deliberately
    // does NOT touch this — so a later parent re-render carrying the SAME original
    // Items instance is recognised as "unchanged" and leaves the applied order
    // intact rather than reverting it. A genuine new Items instance (e.g. a
    // @bind-Items echo or an external replacement) differs by reference and re-syncs.
    // Mirrors Gantt's _lastSeenViewMode and Collapsible's last-param tracking.
    private List<TItem>? _lastItems;
    // CONTROLLED discriminator: the exact list instance/content we last pushed UP via
    // ItemsChanged (re-synced whenever we adopt an authoritative Items). A controlled
    // parent that echoes this back (e.g. a @bind-Items round-trip) is safe to ignore
    // (keep the in-flight _items); anything else — a veto (re-render with the
    // pre-reorder Items unchanged), normalization, or an external replacement — is an
    // authoritative assertion and must win, rolling _items back to it. Mirrors
    // Switch's _lastPushed / DropdownMenuCheckboxItem's _lastPushed discriminator.
    private List<TItem>? _lastPushedItems;
    private int _dragFromIndex = -1;
    private int _dragOverIndex = -1;
    private bool _touchRegistered;
    private bool _pdRegistered;
    private int _focusHandleIndex = -1;
    // #40 (a11y): last reorder message surfaced through the aria-live region.
    private string _reorderAnnouncement = string.Empty;

    protected override void OnParametersSet()
    {
        // controlled-rollback: branch on whether ItemsChanged is bound, mirroring
        // Switch's CheckedChanged.HasDelegate split. A bound ItemsChanged means the
        // parent OWNS the order; rebuilding _items only when "Items differs from the
        // last *incoming* parameter" (the old #144 rule, kept below for the
        // uncontrolled path) cannot tell a parent VETO (re-render with the
        // pre-reorder Items unchanged) apart from "nothing happened" — both look like
        // "same instance as last seen". A veto must roll _items back; the old rule
        // silently kept the rejected optimistic order forever.
        if (ItemsChanged.HasDelegate)
        {
            // CONTROLLED: adopt the incoming Items whenever it is NOT a safe-to-ignore
            // echo of our own last push (_lastPushedItems, set immediately before each
            // ItemsChanged.InvokeAsync in NotifyReordered) — an echo (matching
            // instance, e.g. a @bind-Items round-trip, or matching content) is a no-op
            // that keeps the in-flight _items; anything else — veto, normalization, or
            // an outright replacement — is authoritative and wins.
            //
            // EXCEPT: Items that still match _lastItems (the snapshot from BEFORE this
            // interaction) is NOT a deliberate veto — it is the pre-existing #144
            // contract (regression-tested) for a parent that binds ItemsChanged purely
            // to OBSERVE reorders without echoing them back into Items. That parent's
            // re-render carries the SAME pre-interaction value on every render, which
            // is indistinguishable from "hasn't propagated yet" — and #144 deliberately
            // keeps the local reorder in that case rather than reverting it. A TRUE
            // veto looks different: the parent computes and re-supplies some OTHER
            // value (not what we pushed, not what it had before), which still rolls
            // back correctly below.
            var isEcho = _lastPushedItems is not null
                && (ReferenceEquals(Items, _lastPushedItems) || Items.SequenceEqual(_lastPushedItems));
            var isUnchangedFromBeforeInteraction = _lastItems is not null
                && (ReferenceEquals(Items, _lastItems) || Items.SequenceEqual(_lastItems));
            if (!isEcho && !isUnchangedFromBeforeInteraction)
            {
                _items = Items.ToList();
                _lastPushedItems = _items.ToList();

                // #4 (state-on-data-change): a genuine Items replacement that changes the
                // content rebuilds _items, so any drag indices captured against the OLD
                // list now address a DIFFERENT item — even when the new list is the SAME
                // length (so the out-of-range guard below never fires). The dragged item
                // and drag-over highlight (GetItemClass) and a subsequent OnDrop would
                // then target the wrong row. A refresh mid-drag must abort the drag:
                // unconditionally clear both indices when the content actually changes.
                _dragFromIndex = -1;
                _dragOverIndex = -1;
            }
        }
        else if (!ReferenceEquals(Items, _lastItems) && !_items.SequenceEqual(Items))
        {
            // UNCONTROLLED (#144, state-on-data-change): only rebuild _items when the
            // incoming Items parameter is a genuinely different instance from the one
            // we last saw AND its content actually differs from the order we currently
            // hold. Previously this ran `_items = Items.ToList()` on EVERY render, so
            // any parent re-render that had not (yet) propagated an applied reorder
            // back into Items silently reverted the user's order. A reorder mutates
            // _items in place and deliberately leaves _lastItems pointing at the
            // parent's instance, so a subsequent re-render carrying that SAME instance
            // is seen as "unchanged" and preserves the order; a real replacement
            // differs by reference and re-syncs. The SequenceEqual guard also spares a
            // redundant rebuild when a new-but-content-equal list arrives. Mirrors
            // Gantt's _lastSeenViewMode / Collapsible's last-param tracking.
            _items = Items.ToList();
            _lastPushedItems = _items.ToList();

            _dragFromIndex = -1;
            _dragOverIndex = -1;
        }
        _lastItems = Items;

        // #21 (edge-data): an in-progress drag captures _dragFromIndex/_dragOverIndex
        // against the OLD item count. If the parent shrinks Items mid-drag, those
        // indices can now point past the rebuilt _items and OnDrop's _items[fromIndex]
        // would throw ArgumentOutOfRangeException. Reset any stale indices here so the
        // next drop is a clean no-op rather than a crash. (Belt-and-braces for any path
        // that mutates _items without entering the rebuild branch above.)
        if (_dragFromIndex >= _items.Count)
            _dragFromIndex = -1;
        if (_dragOverIndex >= _items.Count)
            _dragOverIndex = -1;
    }

    // rc.44: HTML5 Drag-and-Drop doesn't fire on touch devices, so we register
    // a parallel touch path that round-trips source/target indices via the
    // interop service. The handler converges with the desktop OnDrop logic.
    //
    // #204: registration is reconciled against the CURRENT Disabled state on
    // every render (not gated on firstRender). A list that mounts Disabled and
    // is enabled later must still pick up the touch handler; a list that becomes
    // disabled must drop it. Element registration needs the DOM, hence here.
    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!Disabled && !_touchRegistered)
        {
            await Interop.RegisterSortableTouch(_containerId, HandleTouchDrop);
            _touchRegistered = true;
        }
        else if (Disabled && _touchRegistered)
        {
            await Interop.UnregisterSortableTouch(_containerId);
            _touchRegistered = false;
        }

        // #204 (a11y): suppress page scroll for the keyboard-reorder keys in JS
        // (a render-time @onkeydown:preventDefault flag lags one event, scrolling
        // on the first arrow press). Registered on the stable container id; the
        // keydown bubbles up from whichever handle is focused. Tab is excluded so
        // focus traversal off the list still works, and SkipEditable keeps arrow
        // keys alive inside editable item templates.
        // Only suppress the reorder keys while keyboard drag handles are actually
        // rendered (Handle && !Disabled). Registering unconditionally swallowed
        // ArrowUp/Down/Home/End from any focusable child in the item template when
        // no handle could consume them. Reconciled every render so toggling
        // Disabled/Handle adds or drops the listener.
        var keyboardHandlesActive = Handle && !Disabled;
        if (keyboardHandlesActive && !_pdRegistered)
        {
            try
            {
                await Interop.RegisterPreventDefaultKeys(
                    _containerId,
                    new[] { "ArrowDown", "ArrowUp", "Home", "End" }
                        .Select(k => new Lumeo.Services.PreventDefaultKeyRule(k, SkipEditable: true)).ToArray());
                _pdRegistered = true;
            }
            catch (JSDisconnectedException) { }
            catch (ObjectDisposedException) { }
            catch (InvalidOperationException) { } // JS interop unavailable during prerender
        }
        else if (!keyboardHandlesActive && _pdRegistered)
        {
            try { await Interop.UnregisterPreventDefaultKeys(_containerId); }
            catch (JSDisconnectedException) { }
            catch (ObjectDisposedException) { }
            _pdRegistered = false;
        }

        // Restore focus to the handle of the just-moved item after a keyboard
        // reorder so arrow-key navigation can continue (best-effort interop).
        if (_focusHandleIndex >= 0)
        {
            var index = _focusHandleIndex;
            _focusHandleIndex = -1;
            await Interop.FocusElement(HandleId(index));
        }
    }

    private async Task HandleTouchDrop(int source, int target)
    {
        if (Disabled) return;
        await InvokeAsync(async () =>
        {
            if (source < 0 || target < 0 || source >= _items.Count || target >= _items.Count || source == target)
                return;

            var item = _items[source];
            _items.RemoveAt(source);
            _items.Insert(target, item);

            _dragFromIndex = -1;
            _dragOverIndex = -1;

            StateHasChanged();
            await NotifyReordered(item, source, target);
        });
    }

    public async ValueTask DisposeAsync()
    {
        if (_touchRegistered)
        {
            try
            {
                await Interop.UnregisterSortableTouch(_containerId);
            }
            catch (JSDisconnectedException) { }
            _touchRegistered = false;
        }

        if (_pdRegistered)
        {
            try
            {
                await Interop.UnregisterPreventDefaultKeys(_containerId);
            }
            catch (JSDisconnectedException) { }
            _pdRegistered = false;
        }
    }

    private string CssClass => Cx.Merge("flex flex-col gap-1", Class);

    private string HandleId(int index) => $"{_containerId}-handle-{index}";

    // #214 (edge-data): the @key on each row must be unique among siblings or Blazor's
    // diff throws ("more than one sibling with the same key"). When a Key selector is
    // provided we honour it. When it is not, the old fallback keyed by the raw item
    // reference, which collides whenever Items holds duplicate values (e.g. two equal
    // strings, interned to the same reference, or any duplicated value type) — throwing
    // on render. Disambiguate duplicates by pairing the value-derived key with the
    // count of equal items that precede it in the current list, so every sibling key is
    // distinct while still tracking item identity for non-duplicate lists.
    private object KeyFor(TItem item, int index)
    {
        var baseKey = Key is not null ? Key(item) : (object?)item;

        var occurrence = 0;
        for (var i = 0; i < index && i < _items.Count; i++)
        {
            var priorKey = Key is not null ? Key(_items[i]) : (object?)_items[i];
            if (Equals(priorKey, baseKey))
                occurrence++;
        }

        // No earlier duplicate: keep the plain key so the common (unique) path is
        // unchanged. Otherwise return a composite that never collides.
        return occurrence == 0 ? (baseKey ?? index) : (baseKey, occurrence);
    }

    private string GetItemClass(int index)
    {
        var classes = "flex items-center rounded-md border border-border/40 bg-card px-3 py-2 transition-all touch-none select-none";
        if (index == _dragFromIndex)
            classes += " opacity-50";
        if (index == _dragOverIndex && index != _dragFromIndex)
            classes += " border-primary border-2";
        if (!Handle && !Disabled)
            classes += " cursor-grab active:cursor-grabbing";
        return classes;
    }

    private void OnDragStart(int index)
    {
        _dragFromIndex = index;
    }

    private void OnDragOver(int index)
    {
        _dragOverIndex = index;
    }

    private void OnDragLeave()
    {
        _dragOverIndex = -1;
    }

    private async Task OnDrop(int toIndex)
    {
        // #21: bound-check both endpoints against the CURRENT list (it may have
        // shrunk mid-drag) before indexing, mirroring HandleTouchDrop's guard.
        if (_dragFromIndex < 0 || _dragFromIndex >= _items.Count
            || toIndex < 0 || toIndex >= _items.Count
            || _dragFromIndex == toIndex)
        {
            _dragFromIndex = -1;
            _dragOverIndex = -1;
            return;
        }

        var fromIndex = _dragFromIndex;
        var item = _items[fromIndex];
        _items.RemoveAt(fromIndex);
        _items.Insert(toIndex, item);

        _dragFromIndex = -1;
        _dragOverIndex = -1;

        await NotifyReordered(item, fromIndex, toIndex);
    }

    private void OnDragEnd()
    {
        _dragFromIndex = -1;
        _dragOverIndex = -1;
    }

    // #204 (a11y): keyboard reordering on the focused drag handle. ArrowUp/Home
    // move the item toward the start, ArrowDown/End toward the end. Mirrors the
    // drag/touch reorder and keeps focus on the moved item's handle. No-op when
    // Disabled (handles aren't rendered then, but stay defensive).
    private async Task OnHandleKeyDown(KeyboardEventArgs e, int index)
    {
        if (Disabled) return;

        int target;
        switch (e.Key)
        {
            case "ArrowUp":
                target = index - 1;
                break;
            case "ArrowDown":
                target = index + 1;
                break;
            case "Home":
                target = 0;
                break;
            case "End":
                target = _items.Count - 1;
                break;
            default:
                return;
        }

        if (target < 0 || target >= _items.Count || target == index)
            return;

        var item = _items[index];
        _items.RemoveAt(index);
        _items.Insert(target, item);

        _focusHandleIndex = target;
        await NotifyReordered(item, index, target);
    }

    private async Task NotifyReordered(TItem item, int oldIndex, int newIndex)
    {
        // #40 (a11y): announce the move through the polite live region so screen
        // readers hear keyboard/touch reorders. {0} is the moved item, {1} its new
        // 1-based position, {2} the list length.
        _reorderAnnouncement = L["Sortable.Moved", item?.ToString() ?? string.Empty, newIndex + 1, _items.Count];

        // #144: emit a snapshot of the freshly-reordered order. Deliberately do NOT
        // update _lastItems here — it must keep tracking the *parent's* last Items
        // instance. Leaving it untouched means a subsequent parent re-render that
        // still carries the original (un-propagated) Items instance is recognised as
        // "unchanged" by OnParametersSet and no longer clobbers the applied order.
        // Uncontrolled usage survives because of this; a controlled @bind-Items echo
        // arrives as a new instance and re-syncs through OnParametersSet normally.
        //
        // controlled-rollback: record this exact snapshot as _lastPushedItems BEFORE
        // invoking ItemsChanged. A controlled parent re-renders synchronously inside
        // InvokeAsync, so OnParametersSet must already see it as "the value we just
        // pushed" to distinguish an accepted echo (keep the in-flight _items) from a
        // veto (parent kept the old Items → roll back). Mirrors Switch's Toggle().
        var pushed = _items.ToList();
        _lastPushedItems = pushed;
        await ItemsChanged.InvokeAsync(pushed);
        if (OnReorder.HasDelegate)
            await OnReorder.InvokeAsync(new SortableMoved(item, oldIndex, newIndex));
    }

    /// <summary>
    /// Payload describing a single reorder: the moved <paramref name="Item"/>
    /// and its <paramref name="OldIndex"/> / <paramref name="NewIndex"/> within
    /// the list. Supplied to <see cref="OnReorder"/>.
    /// </summary>
    public record SortableMoved(TItem Item, int OldIndex, int NewIndex);
}
